CREATE TABLE `package_boxes` (
	`id` int AUTO_INCREMENT NOT NULL,
	`erpCompanyId` int NOT NULL,
	`variantId` int NOT NULL,
	`boxNumber` int NOT NULL,
	`length` decimal(10,2) NOT NULL,
	`width` decimal(10,2) NOT NULL,
	`height` decimal(10,2) NOT NULL,
	`cbm` decimal(10,6) NOT NULL,
	`sortOrder` int NOT NULL DEFAULT 0,
	`createdAt` timestamp NOT NULL DEFAULT (now()),
	`updatedAt` timestamp NOT NULL DEFAULT (now()) ON UPDATE CURRENT_TIMESTAMP,
	CONSTRAINT `package_boxes_id` PRIMARY KEY(`id`)
);

ALTER TABLE `package_boxes` ADD CONSTRAINT `package_boxes_erpCompanyId_erp_companies_id_fk` FOREIGN KEY (`erpCompanyId`) REFERENCES `erp_companies`(`id`) ON DELETE cascade ON UPDATE no action;

ALTER TABLE `package_boxes` ADD CONSTRAINT `package_boxes_variantId_product_variants_id_fk` FOREIGN KEY (`variantId`) REFERENCES `product_variants`(`id`) ON DELETE cascade ON UPDATE no action;

CREATE INDEX `package_boxes_erp_company_idx` ON `package_boxes` (`erpCompanyId`);

CREATE INDEX `package_boxes_variant_idx` ON `package_boxes` (`variantId`);

CREATE INDEX `package_boxes_sort_idx` ON `package_boxes` (`variantId`,`sortOrder`);

